7	//
8	//===----------------------------------------------------------------------===//
9	
10	#ifndef CUDA_TILE_BYTECODE_COMMON_VERSION_H
11	#define CUDA_TILE_BYTECODE_COMMON_VERSION_H
12	
13	#include "llvm/ADT/SmallVector.h"
14	#include "llvm/Support/FormatVariadic.h"
15	
16	#include <cstdint>
17	#include <optional>
18	
19	namespace mlir::cuda_tile {
20	/// This class represents the version of the bytecode format.
21	/// The version is used to determine the compatibility of the bytecode with
22	/// different versions of the Cuda Toolkit and Driver.
23	class BytecodeVersion {
24	public:
25	  /// Construct a bytecode version, which by default will target the current
26	  /// compatibility version of the bytecode format.
27	  BytecodeVersion() : BytecodeVersion(kCurrentCompatibilityVersion) {}
28	
29	  /// Construct a bytecode version from the given major, minor, etc.
30	  /// version numbers. Returns nullopt if the version is not supported.
31	  static std::optional<BytecodeVersion>
32	  fromVersion(uint8_t verMajor, uint8_t verMinor, uint16_t verTag = 0);
33	
34	  /// Returns the major version number.
35	  uint8_t getMajor() const { return verMajor; }
36	
37	  /// Returns the minor version number.
38	  uint8_t getMinor() const { return verMinor; }
39	
40	  /// Returns the version tag.
41	  uint16_t getTag() const { return verTag; }
42	
43	  /// Various comparison operators for comparing versions.
44	  bool operator==(const BytecodeVersion &other) const {
45	    return verMajor == other.verMajor && verMinor == other.verMinor &&
46	           verTag == other.verTag;
47	  }
48	  bool operator!=(const BytecodeVersion &other) const {
49	    return !(*this == other);
50	  }
51	  bool operator<(const BytecodeVersion &other) const {
52	    if (verMajor != other.verMajor)
53	      return verMajor < other.verMajor;
54	    if (verMinor != other.verMinor)
55	      return verMinor < other.verMinor;
56	    return verTag < other.verTag;
57	  }
58	  bool operator<=(const BytecodeVersion &other) const {
59	    return *this < other || *this == other;
60	  }
61	  bool operator>(const BytecodeVersion &other) const { return other < *this; }
62	  bool operator>=(const BytecodeVersion &other) const {
63	    return !(*this < other);
64	  }
65	
66	  /// Convert the version to a human-readable string format.
67	  std::string toString() const {
68	    if (verTag)
69	      return llvm::formatv("{0}.{1}.{2}", verMajor, verMinor, verTag).str();
70	    return llvm::formatv("{0}.{1}", verMajor, verMinor).str();
71	  }
72	
73	  //===--------------------------------------------------------------------===//
74	  // Version Definitions
75	  //===--------------------------------------------------------------------===//
76	
77	  /// The current "compatibility" version of the bytecode format. This version
78	  /// is the one with the widest compatibility range within a major version of
79	  /// the Cuda Toolkit and Driver (generally corresponding to the last major
80	  /// version).
81	  static const BytecodeVersion kCurrentCompatibilityVersion;
82	
83	  /// The current version of the bytecode format. This version corresponds to
84	  /// the most recent version of CUDA Tile IR.
85	  static const BytecodeVersion kCurrentVersion;
86	
87	  /// The version when unified bitfield for optional parameters was introduced.
88	  /// For versions >= 13.3, all optional parameters (Type, Enum, etc.) use a
89	  /// single bitfield. For versions < 13.3, OptionalEnum uses inline flags.
90	  static const BytecodeVersion kUnifiedBitfieldVersion;
91	
92	  /// The minimum supported version of the bytecode format.
93	  static const BytecodeVersion kMinSupportedVersion;
94	
95	private:
96	  /// Constructs a BytecodeVersion object with the given version components.
97	  constexpr BytecodeVersion(uint8_t verMajor, uint8_t verMinor, uint16_t verTag)
98	      : verMajor(verMajor), verMinor(verMinor), verTag(verTag) {}
99	
100	  /// The major version number.
101	  uint8_t verMajor;
102	
103	  /// The minor version number.
104	  uint8_t verMinor;
105	
106	  /// The tag version number.
107	  uint16_t verTag;
108	};
109	
